{
  CURL *curl = curl_easy_init();
  fail_unless(curl != NULL, "curl_easy_init failed");

  /* Test 1: Valid H3 priority with urgency only */
  CURLcode res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=3");
  fail_unless(res == CURLE_OK, "failed to set H3 priority u=3");

  /* Test 2: Valid H3 priority with urgency and incremental flag */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=5,i");
  fail_unless(res == CURLE_OK, "failed to set H3 priority u=5,i");

  /* Test 3: Minimum urgency value */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  fail_unless(res == CURLE_OK, "failed to set H3 priority u=0");

  /* Test 4: Maximum urgency value */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  fail_unless(res == CURLE_OK, "failed to set H3 priority u=7");

  /* Test 5: Invalid urgency (too high) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=8");
  fail_unless(res == CURLE_BAD_FUNCTION_ARGUMENT,
              "should reject urgency value > 7");

  /* Test 6: Invalid format */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "invalid");
  fail_unless(res == CURLE_BAD_FUNCTION_ARGUMENT,
              "should reject invalid format");

  /* Test 7: Null priority string (clear setting) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, NULL);
  fail_unless(res == CURLE_OK, "failed to clear H3 priority");

  curl_easy_cleanup(curl);
}

UNITTEST_STOP

